import { describe, expect, test } from 'bun:test';
import {
  buildR1PhyleEntropyEnvelope,
  validateR1PhyleEntropyEnvelope,
} from './protocol69-r1-phyle-entropy';

describe('protocol69 R1 phyle entropy', () => {
  test('builds a bounded non-executable cooperative escrow envelope', () => {
    const envelope = buildR1PhyleEntropyEnvelope({
      deviceId: 'did:aeon:device:r1',
      phyleId: 'phyle:r1-room',
      sinkProcessId: 'monster:foil',
      surplusUnits: 6,
      entropyWord: 69,
      cadenceMs: 1000,
      timestampMs: 10,
      expiresAtMs: 1010,
    });

    expect(envelope).toEqual(
      expect.objectContaining({
        schemaVersion: 'gnosis.protocol69.r1-phyle-entropy.v1',
        egress: 'PhyleEntropyEscrow',
        executable: false,
        surplusUnits: 6,
        acceptedUnits: 6,
        escrowedUnits: 0,
        entropyWord: 69,
      })
    );
    expect(envelope.redeliveryToken).toContain(
      'r1-phyle-redelivery:phyle:r1-room:monster:foil'
    );
    expect(envelope.projection.expectedProjection).toBe(69);
  });

  test('supports escrowed units for cooperative redelivery', () => {
    const envelope = buildR1PhyleEntropyEnvelope({
      deviceId: 'did:aeon:device:r1',
      phyleId: 'phyle:r1-room',
      sinkProcessId: 'monster:foil',
      surplusUnits: 6,
      acceptedUnits: 2,
      escrowedUnits: 4,
      entropyWord: 69,
      timestampMs: 10,
      expiresAtMs: 1010,
    });

    expect(envelope).toEqual(
      expect.objectContaining({
        acceptedUnits: 2,
        escrowedUnits: 4,
      })
    );
    expect(validateR1PhyleEntropyEnvelope(envelope).escrowedUnits).toBe(4);
  });

  test('rejects executable or malformed phyle entropy envelopes', () => {
    const envelope = buildR1PhyleEntropyEnvelope({
      deviceId: 'did:aeon:device:r1',
      phyleId: 'phyle:r1-room',
      sinkProcessId: 'monster:foil',
      surplusUnits: 1,
      entropyWord: 7,
      timestampMs: 10,
      expiresAtMs: 11,
    });

    expect(validateR1PhyleEntropyEnvelope(envelope).entropyWord).toBe(7);
    expect(() =>
      validateR1PhyleEntropyEnvelope({ ...envelope, executable: true })
    ).toThrow(/non-executable/);
    expect(() =>
      buildR1PhyleEntropyEnvelope({ ...envelope, surplusUnits: 65 })
    ).toThrow(/surplusUnits/);
    expect(() =>
      buildR1PhyleEntropyEnvelope({
        ...envelope,
        surplusUnits: 4,
        acceptedUnits: 3,
        escrowedUnits: 0,
      })
    ).toThrow(/must equal/);
  });
});
